def test_withdrawal_deferred_while_biller_in_hold(auth_headers, unique_key_fn, api_client):
    reg_key = unique_key_fn()
    biller_payload = {
        "biller_name": "Hold Boundary Biller",
        "account_number": "ACC-BVA-" + reg_key[-6:],
        "routing_number": "021000021"
    }
    reg_resp = api_client.post("/billers", json=biller_payload,
                                headers={**auth_headers, "Idempotency-Key": reg_key})
    assert reg_resp.status_code == 201
    biller_id = reg_resp.json()["biller_id"]
    assert reg_resp.json()["status"] == "hold"
    w_payload = {"biller_id": biller_id, "amount": "50.00", "currency": "USD"}
    w_resp = api_client.post("/withdrawals", json=w_payload, headers=auth_headers)
    assert w_resp.status_code in (202, 403)
    if w_resp.status_code == 202:
        assert w_resp.json().get("status") == "deferred"
    else:
        assert w_resp.json().get("code") in ("BILLER_ON_HOLD", "HOLD_PERIOD_ACTIVE")
